// ==UserScript==
// @name         NTB_Document_Upload_Interceptor
// @namespace    https://local.test-tools/
// @version      1.0.0
// @description  Intercept a změna OP/RP bez nutnosti reálného focení dokladů
// @author       Vojtěch
// @match        https://ppe-aplikace.moneta.cz/smeonboarding/*
// @match        https://test1-aplikace.moneta.cz/smeonboarding/*
// @grant        none
// @run-at       document-start
// ==/UserScript==

(function(){
    'use strict';

    const SCRIPT_KEY='__DOCINT_RUNTIME__';
    const previousRuntime=window[SCRIPT_KEY];
    if(previousRuntime&&typeof previousRuntime.destroy==='function'){
        try{
            previousRuntime.destroy({silent:true,reason:'reinit'});
        }catch(e){
            console.warn('[DOC-INT] Nepodařilo se odinstalovat předchozí runtime.',e);
        }
    }

    const cleanupFns=[];
    function registerCleanup(fn){
        if(typeof fn==='function') cleanupFns.push(fn);
        return fn;
    }
    function runCleanups(){
        while(cleanupFns.length){
            const fn=cleanupFns.pop();
            try{fn()}catch(e){console.warn('[DOC-INT] Cleanup chyba:',e)}
        }
    }

    const CONFIG=Object.freeze({
        debug:false,
        enableRuntimeApi:false,
        environments:{
            'ppe-aplikace.moneta.cz':'PPE',
            'test1-aplikace.moneta.cz':'TST1'
        }
    });

    const DEBUG=CONFIG.debug;
    const ENABLE_RUNTIME_API=CONFIG.enableRuntimeApi;

    const ENVIRONMENTS=Object.freeze(CONFIG.environments);
    const SCRIPT_VERSION='1.0.0';

    const base64Samples={
        OP_FRONT:'data:image/jpeg;base64,',
        OP_BACK:'data:image/jpeg;base64,',
        RP_FRONT:'data:image/jpeg;base64,',
    };

    const MATCH_PATH='/openapi/secured/smeonboarding/person/documents/upload';
    const ROUTE_RULES=[
        {id:'OP_FRONT',pattern:/(?:#\/)?identity-card-photo-front(?:[/?#]|$)/i,docType:'IDENTITY_CARD_FRONT'},
        {id:'OP_BACK',pattern:/(?:#\/)?identity-card-photo-back(?:[/?#]|$)/i,docType:'IDENTITY_CARD_BACK'},
        {id:'RP_FRONT',pattern:/#\/secondary-document-photo(?:[?#]|$)/i,docType:'DRIVING_LICENSE_FRONT'}
    ];

    function sampleForDocType(t){
        let sample=null;
        switch(t){
            case'IDENTITY_CARD_FRONT':sample=base64Samples.OP_FRONT;break;
            case'IDENTITY_CARD_BACK':sample=base64Samples.OP_BACK;break;
            case'DRIVING_LICENSE_FRONT':sample=base64Samples.RP_FRONT;break;
            default:return null;
        }
        if(!sample) return null;
        return sample;
    }

    const log=(...a)=>DEBUG&&console.log('%c[DOC-INT]','color:#b22222;font-weight:bold',...a);
    const warn=(...a)=>console.warn('%c[DOC-INT]','color:#b22222;font-weight:bold',...a);
    const getEnvironmentName=()=>ENVIRONMENTS[String(location.hostname||'').toLowerCase()]||'UNKNOWN';
    const replacementInfo=(transport,detected)=>console.info('[DOC-INT] Nahrazen upload dokladu.',{
        env:getEnvironmentName(),
        transport,
        docType:detected&&detected.docType,
        via:detected&&detected.via,
        ruleId:detected&&detected.ruleId,
        url:location.href
    });

    function isTargetUrl(url){
        try{
            const u=new URL(url,location.origin);
            return u.origin===location.origin && u.pathname.startsWith(MATCH_PATH);
        }catch{return (url||'').includes(MATCH_PATH)}
    }
    const curHref=()=>location.href||'';

    function detectDocTypeByRoute(href){
        const h=href||curHref();
        for(const rule of ROUTE_RULES){
            if(rule.pattern.test(h)){
                if(rule.docType) return{docType:rule.docType,via:'route-fixed',ruleId:rule.id};
            }
        }
        return{docType:null,via:'route-miss'};
    }

    function dataUrlToFile(dataUrl,docType){
        if(!/^data:/.test(dataUrl)) return null;
        const [meta,data]=dataUrl.split(',',2);
        const m=meta.match(/^data:(.*?)(;base64)?$/i);
        const mime=(m&&m[1])||'application/octet-stream';
        const b64=!!(m&&m[2]);
        let bin;
        try{
            bin=b64?atob(data):decodeURIComponent(data);
        }catch{return null}
        const len=bin.length, u8=new Uint8Array(len);
        for(let i=0;i<len;i++) u8[i]=bin.charCodeAt(i);
        const ext=mime.includes('png')?'.png':mime.includes('jpeg')||mime.includes('jpg')?'.jpg':mime.includes('pdf')?'.pdf':'';
        const name=(docType||'upload')+'_'+Date.now()+ext;
        try{return new File([u8],name,{type:mime})}catch{return new Blob([u8],{type:mime})}
    }

    function replaceSampleEverywhere(obj,sample){
        const keys=['sample','documentSample','content','image','file'];
        function walk(o){
            if(!o||typeof o!=='object') return;
            for(const k of Object.keys(o)){
                const v=o[k];
                if(typeof v==='object'&&v!==null) walk(v);
                if(keys.includes(k)||k.toLowerCase()==='sample') o[k]=sample;
            }
        }
        walk(obj);
    }
    function setFormDataSmart(fd,sample,fileObj){
        let replaced=false;
        const keys=['sample','document.sample','content','image','file'];
        for(const k of keys){
            if(fd.has(k)){
                if(fileObj instanceof Blob) fd.set(k,fileObj);
                else fd.set(k,sample);
                replaced=true;
            }
        }
        if(!replaced){
            if(fileObj instanceof Blob) fd.set('file',fileObj);
            fd.set('sample',sample);
        }
    }

    (function(){
        const orig=window.fetch?window.fetch.bind(window):null;
        if(!orig){warn('window.fetch není k dispozici – přeskočeno.');return}

        const wrappedFetch=async function(input,init){
            const url=typeof input==='string'?input:input&&input.url;
            if(!url||!isTargetUrl(url)) return orig(input,init);

            let detected=detectDocTypeByRoute(curHref());
            const forced=window.__DOCINT_FORCE?String(window.__DOCINT_FORCE):null;
            if(forced) detected={docType:forced,via:'forced'};

            if(!detected.docType) return orig(input,init);

            const sample=sampleForDocType(detected.docType);
            if(!sample) return orig(input,init);

            let method='GET', headers=new Headers(), body, origReq=null;
            if(input instanceof Request){
                origReq=input;
                method=input.method||method;
                headers=new Headers(input.headers||{});
                if(init&&init.headers){const h2=new Headers(init.headers);h2.forEach((v,k)=>headers.set(k,v))}
                if(init&&init.method) method=init.method;
                if(init&&init.body!==undefined) body=init.body;
                else{try{body=await input.clone().text()}catch{}}
            }else{
                method=(init&&init.method)||method;
                headers=new Headers((init&&init.headers)||{});
                body=init&&init.body;
            }
            if(!body||/^(GET|HEAD)$/i.test(method)) return orig(input,init);

            const ct=(headers.get('content-type')||'').toLowerCase();
            let modified=false, newBody=body;

            if(typeof body==='string'&&(ct.includes('application/json')||body.trim().startsWith('{'))){
                try{
                    const obj=JSON.parse(body);
                    replaceSampleEverywhere(obj,sample);
                    newBody=JSON.stringify(obj);
                    modified=true;
                }catch{}
            }

            if(!modified && typeof URLSearchParams!=='undefined' && body instanceof URLSearchParams){
                if(body.has('sample')){ body.set('sample',sample); modified=true; }
                if(body.has('content')){ body.set('content',sample); modified=true; }
                newBody=body;
            }

            if(!modified && typeof FormData!=='undefined' && body instanceof FormData){
                const fileObj=dataUrlToFile(sample,detected.docType);
                setFormDataSmart(body,sample,fileObj);
                headers.delete('content-type');
                newBody=body;
                modified=true;
            }

            if(!modified) return orig(input,init);
            replacementInfo('fetch',detected);

            const doFetch=()=>{
                if(input instanceof Request){
                    const req=new Request(url,{
                        method,headers,body:newBody,
                        mode:origReq.mode,credentials:origReq.credentials,cache:origReq.cache,
                        redirect:origReq.redirect,referrer:origReq.referrer,referrerPolicy:origReq.referrerPolicy,
                        integrity:origReq.integrity,keepalive:origReq.keepalive,signal:(init&&init.signal)||undefined
                    });
                    return orig(req);
                }else{
                    const newInit=Object.assign({},init,{body:newBody,headers});
                    return orig(url,newInit);
                }
            };

            const resp=await doFetch();
            return resp;
        };
        window.fetch=wrappedFetch;
        registerCleanup(()=>{ if(window.fetch===wrappedFetch) window.fetch=orig; });
    })();

    (function(){
        const oOpen=XMLHttpRequest.prototype.open;
        const oSend=XMLHttpRequest.prototype.send;

        const wrappedOpen=function(method,url,async,user,pass){
            this.__docint={method,url,modified:false,detected:null};
            return oOpen.apply(this,arguments);
        };
        XMLHttpRequest.prototype.open=wrappedOpen;

        const wrappedSend=function(body){
            try{
                const info=this.__docint||{};
                const url=info.url||'';
                if(!isTargetUrl(url) || !body) return oSend.apply(this,arguments);

                let detected=detectDocTypeByRoute(curHref());
                const forced=window.__DOCINT_FORCE?String(window.__DOCINT_FORCE):null;
                if(forced) detected={docType:forced,via:'forced'};

                if(!detected.docType) return oSend.apply(this,arguments);

                const sample=sampleForDocType(detected.docType);
                if(!sample) return oSend.apply(this,arguments);

                let newBody=body, modified=false;

                if(typeof body==='string'){
                    try{
                        const obj=JSON.parse(body);
                        replaceSampleEverywhere(obj,sample);
                        newBody=JSON.stringify(obj);
                        modified=true;
                    }catch{}
                }

                if(!modified && typeof URLSearchParams!=='undefined' && body instanceof URLSearchParams){
                    if(body.has('sample')){ body.set('sample',sample); modified=true; }
                    if(body.has('content')){ body.set('content',sample); modified=true; }
                    newBody=body;
                }

                if(!modified && typeof FormData!=='undefined' && body instanceof FormData){
                    const fileObj=dataUrlToFile(sample,detected.docType);
                    setFormDataSmart(body,sample,fileObj);
                    newBody=body;
                    modified=true;
                }

                if(modified){
                    replacementInfo('xhr',detected);
                    this.__docint.modified=true;
                    this.__docint.detected=detected;
                    return oSend.call(this,newBody);
                }
                return oSend.apply(this,arguments);
            }catch(e){
                warn('XHR interceptor chyba:',e);
                return oSend.apply(this,arguments);
            }
        };
        XMLHttpRequest.prototype.send=wrappedSend;
        registerCleanup(()=>{
            if(XMLHttpRequest.prototype.open===wrappedOpen) XMLHttpRequest.prototype.open=oOpen;
            if(XMLHttpRequest.prototype.send===wrappedSend) XMLHttpRequest.prototype.send=oSend;
        });
    })();

    function destroyRuntime({silent=false}={}){
        runCleanups();
        delete window[SCRIPT_KEY];
        if(!silent) console.info('[DOC-INT] Document interceptor odinstalován.');
    }

    window[SCRIPT_KEY]=ENABLE_RUNTIME_API?{
        destroy:destroyRuntime,
        force(docType){ window.__DOCINT_FORCE=docType?String(docType):''; },
        clearForce(){ try{ delete window.__DOCINT_FORCE; }catch{ window.__DOCINT_FORCE=''; } },
        reset(){}
    }:{
        destroy:destroyRuntime
    };
    log(`Interceptor v${SCRIPT_VERSION} nahrán: JSON/FormData/URLParams, File+base64.`);
    console.info('[DOC-INT] NTB_Document_Upload_Interceptor aktivní.',{
        version:SCRIPT_VERSION,
        env:getEnvironmentName(),
        runtimeApi:ENABLE_RUNTIME_API?'enabled':'disabled'
    });
})();
